import React, { useEffect } from 'react';
import { Linking, Alert } from 'react-native';
import { NavigationContainer } from '@react-navigation/native';
import { createStackNavigator } from '@react-navigation/stack';

const Stack = createStackNavigator();

const ProfileScreen = ({ route }) => {
  const { userId } = route.params;
  return <Text>Profile Screen for User ID: {userId}</Text>;
};

const PaymentConfirmScreen = () => {
  return <Text>Payment Confirmation Screen</Text>;
};

const App = () => {
  useEffect(() => {
    const handleDeepLink = (event) => {
      const { url } = event;
      const route = parseUrl(url);
      if (route) {
        navigateTo(route);
      } else {
        Alert.alert('Invalid URL', 'The provided URL is not valid.');
      }
    };

    const parseUrl = (url) => {
      const allowlist = ['myapp://profile', 'myapp://payment/confirm'];
      const urlObj = new URL(url);
      if (!allowlist.includes(`${urlObj.protocol}//${urlObj.host}${urlObj.pathname}`)) {
        return null;
      }
      const pathSegments = urlObj.pathname.split('/').filter(Boolean);
      if (urlObj.host === 'profile' && pathSegments.length === 2) {
        return { screen: 'Profile', params: { userId: pathSegments[1] } };
      } else if (urlObj.host === 'payment' && pathSegments[0] === 'confirm') {
        return { screen: 'PaymentConfirm' };
      }
      return null;
    };

    const navigateTo = (route) => {
      if (route.screen === 'Profile') {
        navigationRef.current?.navigate('Profile', route.params);
      } else if (route.screen === 'PaymentConfirm') {
        navigationRef.current?.navigate('PaymentConfirm');
      }
    };

    Linking.addEventListener('url', handleDeepLink);
    Linking.getInitialURL().then((url) => {
      if (url) {
        handleDeepLink({ url });
      }
    });

    return () => {
      Linking.removeEventListener('url', handleDeepLink);
    };
  }, []);

  return (
    <NavigationContainer ref={navigationRef}>
      <Stack.Navigator>
        <Stack.Screen name="Profile" component={ProfileScreen} />
        <Stack.Screen name="PaymentConfirm" component={PaymentConfirmScreen} />
      </Stack.Navigator>
    </NavigationContainer>
  );
};

const navigationRef = React.createRef();

export default App;